import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import App from './App';

describe('Accessible Combobox', () => {
  it('input has role=combobox', () => {
    render(<App />);
    expect(screen.getByTestId('combo-input')).toHaveAttribute('role', 'combobox');
  });

  it('input has aria-expanded=false when closed', () => {
    render(<App />);
    expect(screen.getByTestId('combo-input')).toHaveAttribute('aria-expanded', 'false');
  });

  it('input has aria-autocomplete=list', () => {
    render(<App />);
    expect(screen.getByTestId('combo-input')).toHaveAttribute('aria-autocomplete', 'list');
  });

  it('shows listbox when typing', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('combo-input'), { target: { value: 'fra' } });
    expect(screen.getByTestId('listbox')).toBeInTheDocument();
    expect(screen.getByTestId('listbox')).toHaveAttribute('role', 'listbox');
  });

  it('filters options by query', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('combo-input'), { target: { value: 'aus' } });
    expect(screen.getByTestId('option-0')).toHaveTextContent('Australia');
    expect(screen.getByTestId('option-1')).toHaveTextContent('Austria');
  });

  it('arrow down highlights next option', () => {
    render(<App />);
    const input = screen.getByTestId('combo-input');
    fireEvent.change(input, { target: { value: 'a' } });
    fireEvent.keyDown(input, { key: 'ArrowDown' });
    expect(screen.getByTestId('option-0')).toHaveClass('combo__option--active');
    fireEvent.keyDown(input, { key: 'ArrowDown' });
    expect(screen.getByTestId('option-1')).toHaveClass('combo__option--active');
  });

  it('enter selects highlighted option', () => {
    render(<App />);
    const input = screen.getByTestId('combo-input');
    fireEvent.change(input, { target: { value: 'franc' } });
    fireEvent.keyDown(input, { key: 'ArrowDown' });
    fireEvent.keyDown(input, { key: 'Enter' });
    expect(screen.getByTestId('selected-value')).toHaveTextContent('France');
  });

  it('escape closes listbox', () => {
    render(<App />);
    const input = screen.getByTestId('combo-input');
    fireEvent.change(input, { target: { value: 'a' } });
    expect(screen.getByTestId('listbox')).toBeInTheDocument();
    fireEvent.keyDown(input, { key: 'Escape' });
    expect(screen.queryByTestId('listbox')).not.toBeInTheDocument();
  });

  it('clicking an option selects it', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('combo-input'), { target: { value: 'japan' } });
    fireEvent.click(screen.getByTestId('option-0'));
    expect(screen.getByTestId('selected-value')).toHaveTextContent('Japan');
  });

  it('shows no results message', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('combo-input'), { target: { value: 'zzzzz' } });
    expect(screen.getByTestId('no-results')).toBeInTheDocument();
  });

  it('options have role=option', () => {
    render(<App />);
    fireEvent.change(screen.getByTestId('combo-input'), { target: { value: 'can' } });
    expect(screen.getByTestId('option-0')).toHaveAttribute('role', 'option');
  });
});

