import React, { useState, useRef, useEffect, useId } from 'react';
import './styles.css';

interface ComboboxProps {
  options: string[];
  label: string;
}

export const Combobox: React.FC<ComboboxProps> = ({ options, label }) => {
  const [query, setQuery] = useState('');
  const [isOpen, setIsOpen] = useState(false);
  const [activeIndex, setActiveIndex] = useState(-1);
  const [selectedValue, setSelectedValue] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);
  const listRef = useRef<HTMLDivElement>(null);
  const baseId = useId();
  const listboxId = `${baseId}-listbox`;

  const filtered = options.filter(o => o.toLowerCase().includes(query.toLowerCase()));

  const getOptionId = (index: number) => `${baseId}-option-${index}`;

  const handleSelect = (value: string) => {
    setSelectedValue(value);
    setQuery(value);
    setIsOpen(false);
    setActiveIndex(-1);
    inputRef.current?.focus();
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    switch (e.key) {
      case 'ArrowDown':
        e.preventDefault();
        if (!isOpen) { setIsOpen(true); }
        setActiveIndex(prev => Math.min(prev + 1, filtered.length - 1));
        break;
      case 'ArrowUp':
        e.preventDefault();
        setActiveIndex(prev => Math.max(prev - 1, 0));
        break;
      case 'Enter':
        e.preventDefault();
        if (activeIndex >= 0 && activeIndex < filtered.length) {
          handleSelect(filtered[activeIndex]);
        }
        break;
      case 'Escape':
        setIsOpen(false);
        setActiveIndex(-1);
        break;
    }
  };

  useEffect(() => {
    if (activeIndex >= 0 && listRef.current) {
      const active = listRef.current.children[activeIndex] as HTMLElement;
      active?.scrollIntoView?.({ block: 'nearest' });
    }
  }, [activeIndex]);

  // Close on outside click
  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (!inputRef.current?.parentElement?.contains(e.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handler);
    return () => document.removeEventListener('mousedown', handler);
  }, []);

  const showListbox = isOpen && query.length > 0;

  return (
    <div className="combo">
      <label className="combo__label" id={`${baseId}-label`}>{label}</label>
      <div className="combo__wrapper">
        <input
          ref={inputRef}
          data-testid="combo-input"
          className="combo__input"
          role="combobox"
          aria-expanded={showListbox}
          aria-autocomplete="list"
          aria-controls={listboxId}
          aria-activedescendant={activeIndex >= 0 ? getOptionId(activeIndex) : undefined}
          aria-labelledby={`${baseId}-label`}
          value={query}
          onChange={e => {
            setQuery(e.target.value);
            setIsOpen(true);
            setActiveIndex(-1);
          }}
          onFocus={() => { if (query) setIsOpen(true); }}
          onKeyDown={handleKeyDown}
          placeholder="Type to search…"
        />

        {showListbox && (
          <div ref={listRef} data-testid="listbox" id={listboxId} className="combo__listbox" role="listbox">
            {filtered.length === 0 ? (
              <div data-testid="no-results" className="combo__empty" role="status">
                No results found
              </div>
            ) : (
              filtered.map((option, i) => (
                <div
                  key={option}
                  id={getOptionId(i)}
                  data-testid={`option-${i}`}
                  className={`combo__option${i === activeIndex ? ' combo__option--active' : ''}`}
                  role="option"
                  aria-selected={i === activeIndex}
                  onClick={() => handleSelect(option)}
                >
                  {option}
                </div>
              ))
            )}
          </div>
        )}
      </div>
      <p data-testid="selected-value" className="combo__selected">
        {selectedValue ? `Selected: ${selectedValue}` : 'No selection'}
      </p>
    </div>
  );
};
